/**
 * Notification service — handles sending notifications for order lifecycle events.
 *
 * Subscribes to EventBus events (order:created, order:status-changed) to send
 * notifications. This follows the project's event-driven architecture where
 * services communicate via events rather than direct calls, promoting loose
 * coupling and making it easy to add new notification channels without
 * modifying the emitting services.
 */

import type { Order } from '../models/order.js';
import type { User } from '../models/user.js';
import type { OrderStatus } from '../models/order.js';
import type { EventBus } from '../events/event-bus.js';
import type { OrderCreatedEvent, OrderStatusChangedEvent } from '../events/event-types.js';
import { Logger } from '../utils/logger.js';

export interface Notification {
  id: string;
  recipient: string;
  subject: string;
  body: string;
  sentAt: Date;
}

let nextId = 1;

function generateNotificationId(): string {
  return `notif-${String(nextId++).padStart(4, '0')}`;
}

export function resetNotificationIdCounter(): void {
  nextId = 1;
}

export class NotificationService {
  private logger = new Logger('NotificationService');
  private notifications: Notification[] = [];

  constructor(private eventBus: EventBus) {
    this.subscribeToEvents();
  }

  /**
   * Subscribe to relevant events on the event bus.
   */
  private subscribeToEvents(): void {
    this.eventBus.on<OrderCreatedEvent>('order:created', (event) => {
      this.handleOrderCreated(event.order, event.user);
    });

    this.eventBus.on<OrderStatusChangedEvent>('order:status-changed', (event) => {
      this.handleOrderStatusChanged(event.order, event.previousStatus as OrderStatus, event.newStatus as OrderStatus);
    });
  }

  /**
   * Handle order:created event — sends confirmation to the user.
   */
  private handleOrderCreated(order: Order, user: User): void {
    this.logger.info(`Sending order confirmation for order ${order.id}`);

    const itemSummary = order.items
      .map((item) => `${item.name} x${item.quantity}`)
      .join(', ');

    this.sendNotification({
      recipient: user.email,
      subject: `Order Confirmation: ${order.id}`,
      body: `Your order has been placed. Items: ${itemSummary}. Total: $${order.total.toFixed(2)}`,
    });
  }

  /**
   * Handle order:status-changed event — notifies user of status update.
   */
  private handleOrderStatusChanged(order: Order, previousStatus: OrderStatus, newStatus: OrderStatus): void {
    this.logger.info(
      `Sending status update for order ${order.id}: ${previousStatus} -> ${newStatus}`,
    );

    this.sendNotification({
      recipient: order.userId,
      subject: `Order Update: ${order.id}`,
      body: `Your order status has changed from ${previousStatus} to ${newStatus}.`,
    });
  }

  /**
   * Send a notification (in-memory for this demo).
   */
  private sendNotification(params: {
    recipient: string;
    subject: string;
    body: string;
  }): void {
    const notification: Notification = {
      id: generateNotificationId(),
      recipient: params.recipient,
      subject: params.subject,
      body: params.body,
      sentAt: new Date(),
    };
    this.notifications.push(notification);
    this.logger.info(`Notification sent: ${notification.id} to ${params.recipient}`);
  }

  /**
   * Get all sent notifications.
   */
  getNotifications(): Notification[] {
    return [...this.notifications];
  }

  /**
   * Get notifications for a specific recipient.
   */
  getNotificationsForRecipient(recipient: string): Notification[] {
    return this.notifications.filter((n) => n.recipient === recipient);
  }

  /**
   * Get the count of sent notifications.
   */
  getNotificationCount(): number {
    return this.notifications.length;
  }

  /**
   * Clear all notifications (useful for testing).
   */
  clearNotifications(): void {
    this.notifications = [];
  }
}

/**
 * Order service — business logic for order management.
 *
 * Depends on:
 * - OrderRepository (data layer) for persistence
 * - UserRepository (data layer) for user validation
 * - EventBus (event system) for publishing order lifecycle events
 *
 * Notifications are handled by NotificationService, which subscribes to
 * EventBus events. This keeps OrderService decoupled from notification
 * concerns, consistent with the project's event-driven architecture.
 */

import type { Order, CreateOrderInput, OrderStatus } from '../models/order.js';
import { calculateOrderTotal } from '../models/order.js';
import type { OrderRepository } from '../repositories/order.repository.js';
import type { UserRepository } from '../repositories/user.repository.js';
import type { EventBus } from '../events/event-bus.js';
import { Logger } from '../utils/logger.js';

let nextId = 1;

function generateId(): string {
  return `order-${String(nextId++).padStart(4, '0')}`;
}

export function resetOrderIdCounter(): void {
  nextId = 1;
}

export class OrderService {
  private logger = new Logger('OrderService');

  constructor(
    private orderRepository: OrderRepository,
    private userRepository: UserRepository,
    private eventBus: EventBus,
  ) {}

  /**
   * Create a new order for a user.
   */
  async createOrder(input: CreateOrderInput): Promise<Order> {
    this.logger.info(`Creating order for user: ${input.userId}`);

    // Validate user exists
    const user = this.userRepository.findById(input.userId);
    if (!user) {
      throw new Error(`User not found: ${input.userId}`);
    }

    // Validate order has items
    if (input.items.length === 0) {
      throw new Error('Order must have at least one item');
    }

    const now = new Date();
    const order: Order = {
      id: generateId(),
      userId: input.userId,
      items: input.items,
      total: calculateOrderTotal(input.items),
      status: 'pending',
      createdAt: now,
      updatedAt: now,
    };

    this.orderRepository.save(order);

    await this.eventBus.emit({
      type: 'order:created',
      order,
      user,
      timestamp: now,
    });

    return order;
  }

  /**
   * Get an order by ID.
   */
  getOrder(id: string): Order | undefined {
    return this.orderRepository.findById(id);
  }

  /**
   * Update order status.
   */
  async updateOrderStatus(id: string, newStatus: OrderStatus): Promise<Order> {
    this.logger.info(`Updating order ${id} status to: ${newStatus}`);

    const order = this.orderRepository.findById(id);
    if (!order) {
      throw new Error(`Order not found: ${id}`);
    }

    const previousStatus = order.status;

    // Validate status transition
    if (!this.isValidStatusTransition(previousStatus, newStatus)) {
      throw new Error(
        `Invalid status transition: ${previousStatus} -> ${newStatus}`,
      );
    }

    const updated = this.orderRepository.update(id, {
      status: newStatus,
      updatedAt: new Date(),
    });

    await this.eventBus.emit({
      type: 'order:status-changed',
      order: updated,
      previousStatus,
      newStatus,
      timestamp: new Date(),
    });

    return updated;
  }

  /**
   * List orders for a user.
   */
  listUserOrders(userId: string): Order[] {
    return this.orderRepository.findByUserId(userId);
  }

  /**
   * List orders by status.
   */
  listOrdersByStatus(status: OrderStatus): Order[] {
    return this.orderRepository.findByStatus(status);
  }

  /**
   * Validate that a status transition is allowed.
   */
  private isValidStatusTransition(
    from: OrderStatus,
    to: OrderStatus,
  ): boolean {
    const transitions: Record<OrderStatus, OrderStatus[]> = {
      pending: ['confirmed', 'cancelled'],
      confirmed: ['shipped', 'cancelled'],
      shipped: ['delivered'],
      delivered: [],
      cancelled: [],
    };
    return transitions[from].includes(to);
  }
}

import { describe, it, expect, beforeEach } from 'vitest';
import { Database } from '../../src/utils/database.js';
import { UserRepository } from '../../src/repositories/user.repository.js';
import { OrderRepository } from '../../src/repositories/order.repository.js';
import { EventBus } from '../../src/events/event-bus.js';
import { OrderService, resetOrderIdCounter } from '../../src/services/order.service.js';
import { NotificationService, resetNotificationIdCounter } from '../../src/services/notification.service.js';
import type { User } from '../../src/models/user.js';

describe('OrderService', () => {
  let db: Database;
  let userRepo: UserRepository;
  let orderRepo: OrderRepository;
  let eventBus: EventBus;
  let notificationService: NotificationService;
  let service: OrderService;
  let testUser: User;

  beforeEach(() => {
    db = new Database();
    userRepo = new UserRepository(db);
    orderRepo = new OrderRepository(db);
    eventBus = new EventBus();
    notificationService = new NotificationService(eventBus);
    service = new OrderService(orderRepo, userRepo, eventBus);
    resetOrderIdCounter();
    resetNotificationIdCounter();

    // Create a test user
    testUser = {
      id: 'user-1',
      name: 'Alice',
      email: 'alice@example.com',
      role: 'member',
      createdAt: new Date(),
      updatedAt: new Date(),
    };
    userRepo.save(testUser);
  });

  describe('createOrder', () => {
    it('should create an order and emit event', async () => {
      const order = await service.createOrder({
        userId: 'user-1',
        items: [
          { productId: 'p1', name: 'Widget', quantity: 2, unitPrice: 10 },
        ],
      });

      expect(order.id).toBe('order-0001');
      expect(order.userId).toBe('user-1');
      expect(order.total).toBe(20);
      expect(order.status).toBe('pending');

      const events = eventBus.getEventLog();
      expect(events).toHaveLength(1);
      expect(events[0]?.type).toBe('order:created');
    });

    it('should trigger notification via event bus on order creation', async () => {
      await service.createOrder({
        userId: 'user-1',
        items: [
          { productId: 'p1', name: 'Widget', quantity: 2, unitPrice: 10 },
        ],
      });

      const notifications = notificationService.getNotifications();
      expect(notifications).toHaveLength(1);
      expect(notifications[0]?.recipient).toBe('alice@example.com');
      expect(notifications[0]?.subject).toContain('Order Confirmation');
      expect(notifications[0]?.body).toContain('Widget x2');
      expect(notifications[0]?.body).toContain('$20.00');
    });

    it('should throw for non-existent user', async () => {
      await expect(
        service.createOrder({
          userId: 'nonexistent',
          items: [{ productId: 'p1', name: 'Widget', quantity: 1, unitPrice: 10 }],
        }),
      ).rejects.toThrow('User not found');
    });

    it('should throw for empty items', async () => {
      await expect(
        service.createOrder({ userId: 'user-1', items: [] }),
      ).rejects.toThrow('at least one item');
    });

    it('should calculate total from items', async () => {
      const order = await service.createOrder({
        userId: 'user-1',
        items: [
          { productId: 'p1', name: 'Widget', quantity: 2, unitPrice: 10 },
          { productId: 'p2', name: 'Gadget', quantity: 1, unitPrice: 25 },
        ],
      });

      expect(order.total).toBe(45);
    });
  });

  describe('getOrder', () => {
    it('should get an existing order', async () => {
      const created = await service.createOrder({
        userId: 'user-1',
        items: [{ productId: 'p1', name: 'Widget', quantity: 1, unitPrice: 10 }],
      });

      const found = service.getOrder(created.id);
      expect(found).toBeDefined();
      expect(found?.total).toBe(10);
    });
  });

  describe('updateOrderStatus', () => {
    it('should update status and emit event', async () => {
      const order = await service.createOrder({
        userId: 'user-1',
        items: [{ productId: 'p1', name: 'Widget', quantity: 1, unitPrice: 10 }],
      });

      const updated = await service.updateOrderStatus(order.id, 'confirmed');
      expect(updated.status).toBe('confirmed');

      const events = eventBus.getEventLog();
      expect(events).toHaveLength(2);
      expect(events[0]?.type).toBe('order:created');
      expect(events[1]?.type).toBe('order:status-changed');
    });

    it('should trigger notification via event bus on status update', async () => {
      const order = await service.createOrder({
        userId: 'user-1',
        items: [{ productId: 'p1', name: 'Widget', quantity: 1, unitPrice: 10 }],
      });

      notificationService.clearNotifications();
      await service.updateOrderStatus(order.id, 'confirmed');

      const notifications = notificationService.getNotifications();
      expect(notifications).toHaveLength(1);
      expect(notifications[0]?.recipient).toBe('user-1');
      expect(notifications[0]?.subject).toContain('Order Update');
      expect(notifications[0]?.body).toContain('pending');
      expect(notifications[0]?.body).toContain('confirmed');
    });

    it('should reject invalid status transition', async () => {
      const order = await service.createOrder({
        userId: 'user-1',
        items: [{ productId: 'p1', name: 'Widget', quantity: 1, unitPrice: 10 }],
      });

      await expect(
        service.updateOrderStatus(order.id, 'delivered'),
      ).rejects.toThrow('Invalid status transition');
    });

    it('should follow valid status flow', async () => {
      const order = await service.createOrder({
        userId: 'user-1',
        items: [{ productId: 'p1', name: 'Widget', quantity: 1, unitPrice: 10 }],
      });

      await service.updateOrderStatus(order.id, 'confirmed');
      await service.updateOrderStatus(order.id, 'shipped');
      const delivered = await service.updateOrderStatus(order.id, 'delivered');

      expect(delivered.status).toBe('delivered');
    });

    it('should reject transitions from terminal states', async () => {
      const order = await service.createOrder({
        userId: 'user-1',
        items: [{ productId: 'p1', name: 'Widget', quantity: 1, unitPrice: 10 }],
      });

      await service.updateOrderStatus(order.id, 'cancelled');

      await expect(
        service.updateOrderStatus(order.id, 'confirmed'),
      ).rejects.toThrow('Invalid status transition');
    });

    it('should throw for non-existent order', async () => {
      await expect(
        service.updateOrderStatus('nonexistent', 'confirmed'),
      ).rejects.toThrow('Order not found');
    });
  });

  describe('listUserOrders', () => {
    it('should list orders for a user', async () => {
      await service.createOrder({
        userId: 'user-1',
        items: [{ productId: 'p1', name: 'Widget', quantity: 1, unitPrice: 10 }],
      });
      await service.createOrder({
        userId: 'user-1',
        items: [{ productId: 'p2', name: 'Gadget', quantity: 1, unitPrice: 20 }],
      });

      const orders = service.listUserOrders('user-1');
      expect(orders).toHaveLength(2);
    });
  });

  describe('listOrdersByStatus', () => {
    it('should list orders by status', async () => {
      const o1 = await service.createOrder({
        userId: 'user-1',
        items: [{ productId: 'p1', name: 'Widget', quantity: 1, unitPrice: 10 }],
      });
      await service.createOrder({
        userId: 'user-1',
        items: [{ productId: 'p2', name: 'Gadget', quantity: 1, unitPrice: 20 }],
      });

      await service.updateOrderStatus(o1.id, 'confirmed');

      const pending = service.listOrdersByStatus('pending');
      expect(pending).toHaveLength(1);

      const confirmed = service.listOrdersByStatus('confirmed');
      expect(confirmed).toHaveLength(1);
    });
  });
});

import { describe, it, expect, beforeEach } from 'vitest';
import {
  NotificationService,
  resetNotificationIdCounter,
} from '../../src/services/notification.service.js';
import { EventBus } from '../../src/events/event-bus.js';
import type { Order } from '../../src/models/order.js';
import type { User } from '../../src/models/user.js';

describe('NotificationService', () => {
  let eventBus: EventBus;
  let service: NotificationService;

  const testUser: User = {
    id: 'user-1',
    name: 'Alice',
    email: 'alice@example.com',
    role: 'member',
    createdAt: new Date(),
    updatedAt: new Date(),
  };

  function makeOrder(overrides: Partial<Order> = {}): Order {
    return {
      id: 'order-1',
      userId: 'user-1',
      items: [
        { productId: 'p1', name: 'Widget', quantity: 2, unitPrice: 10 },
      ],
      total: 20,
      status: 'pending',
      createdAt: new Date(),
      updatedAt: new Date(),
      ...overrides,
    };
  }

  beforeEach(() => {
    eventBus = new EventBus();
    service = new NotificationService(eventBus);
    resetNotificationIdCounter();
  });

  describe('order:created event', () => {
    it('should send notification with order confirmation', async () => {
      const order = makeOrder();
      await eventBus.emit({
        type: 'order:created',
        order,
        user: testUser,
        timestamp: new Date(),
      });

      const notifications = service.getNotifications();
      expect(notifications).toHaveLength(1);
      expect(notifications[0]?.recipient).toBe('alice@example.com');
      expect(notifications[0]?.subject).toContain('Order Confirmation');
      expect(notifications[0]?.body).toContain('Widget x2');
      expect(notifications[0]?.body).toContain('$20.00');
    });

    it('should include all items in notification body', async () => {
      const order = makeOrder({
        items: [
          { productId: 'p1', name: 'Widget', quantity: 2, unitPrice: 10 },
          { productId: 'p2', name: 'Gadget', quantity: 1, unitPrice: 25 },
        ],
        total: 45,
      });

      await eventBus.emit({
        type: 'order:created',
        order,
        user: testUser,
        timestamp: new Date(),
      });

      const notifications = service.getNotifications();
      expect(notifications[0]?.body).toContain('Widget x2');
      expect(notifications[0]?.body).toContain('Gadget x1');
    });
  });

  describe('order:status-changed event', () => {
    it('should send notification on status change', async () => {
      const order = makeOrder({ status: 'confirmed' });
      await eventBus.emit({
        type: 'order:status-changed',
        order,
        previousStatus: 'pending',
        newStatus: 'confirmed',
        timestamp: new Date(),
      });

      const notifications = service.getNotifications();
      expect(notifications).toHaveLength(1);
      expect(notifications[0]?.subject).toContain('Order Update');
      expect(notifications[0]?.body).toContain('pending');
      expect(notifications[0]?.body).toContain('confirmed');
    });

    it('should use order userId as recipient', async () => {
      const order = makeOrder({ userId: 'user-42' });
      await eventBus.emit({
        type: 'order:status-changed',
        order,
        previousStatus: 'pending',
        newStatus: 'confirmed',
        timestamp: new Date(),
      });

      const notifications = service.getNotifications();
      expect(notifications[0]?.recipient).toBe('user-42');
    });
  });

  describe('notification management', () => {
    it('should count notifications', async () => {
      expect(service.getNotificationCount()).toBe(0);

      await eventBus.emit({
        type: 'order:status-changed',
        order: makeOrder(),
        previousStatus: 'pending',
        newStatus: 'confirmed',
        timestamp: new Date(),
      });
      expect(service.getNotificationCount()).toBe(1);
    });

    it('should filter by recipient', async () => {
      await eventBus.emit({
        type: 'order:created',
        order: makeOrder(),
        user: testUser,
        timestamp: new Date(),
      });

      expect(service.getNotificationsForRecipient('alice@example.com')).toHaveLength(1);
      expect(service.getNotificationsForRecipient('bob@example.com')).toHaveLength(0);
    });

    it('should clear notifications', async () => {
      await eventBus.emit({
        type: 'order:status-changed',
        order: makeOrder(),
        previousStatus: 'pending',
        newStatus: 'confirmed',
        timestamp: new Date(),
      });
      service.clearNotifications();
      expect(service.getNotificationCount()).toBe(0);
    });

    it('should generate sequential notification IDs', async () => {
      await eventBus.emit({
        type: 'order:status-changed',
        order: makeOrder(),
        previousStatus: 'pending',
        newStatus: 'confirmed',
        timestamp: new Date(),
      });
      await eventBus.emit({
        type: 'order:status-changed',
        order: makeOrder({ id: 'order-2' }),
        previousStatus: 'confirmed',
        newStatus: 'shipped',
        timestamp: new Date(),
      });

      const notifications = service.getNotifications();
      expect(notifications[0]?.id).toBe('notif-0001');
      expect(notifications[1]?.id).toBe('notif-0002');
    });
  });

  describe('event-driven integration', () => {
    it('should handle both event types', async () => {
      const order = makeOrder();
      await eventBus.emit({
        type: 'order:created',
        order,
        user: testUser,
        timestamp: new Date(),
      });
      await eventBus.emit({
        type: 'order:status-changed',
        order: { ...order, status: 'confirmed' },
        previousStatus: 'pending',
        newStatus: 'confirmed',
        timestamp: new Date(),
      });

      expect(service.getNotificationCount()).toBe(2);

      const notifications = service.getNotifications();
      expect(notifications[0]?.subject).toContain('Order Confirmation');
      expect(notifications[1]?.subject).toContain('Order Update');
    });
  });
});

